import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirRouteNames } from '../routeNames';
import { ExpansionPanel, ExpansionPanelSummary, ExpansionPanelDetails, Button } from '@material-ui/core';
import { hirSettingStrings } from './config';
import { hirSettingActions } from './actions';
import { hirUtilStrings, hirAppActions as appActions, hirAlertActions as alertAction,
    headerActions, headerStrings, breadCrumbActions, MyTable, EditableCellMapFormat,
    history
} from '../utils';

let settings = [
    {
        _id : 1,
        name : "revenueCategories",
        header : "Revenue Category",
        values : [
            {name : "record", value : "New Folder"},
            {name : "appointment", value : "Appointments"}
        ]
    },
    {
        _id : 1,
        name : "units",
        header : "Hospital Units",
        values : [
            {name : "record", value : "Records"},
            {name : "physiotherapy", value : "Physiotherapy"}
        ]
    },
]
const style = theme => ({
    root: {
    },
    summary : {
        backgroundColor : theme.colors.primary1,
        color : theme.colors.white,
    },
    details : {
        padding : 5,
    }
})
class _HIRSettings extends Component {
    constructor(props) {
        super(props);
        this.state = {
            settings : null,
            settingsUnused : null,
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "SETTINGS",
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : hirRouteNames.dashboard},
            {name : "Settings", path : hirRouteNames.settings}
        ])(dispatch);
    }
    componentWillMount(){
        const {
            [hirUtilStrings.myProfile] : profile
        } = this.props;
        if(!profile || [0, 11].indexOf(profile.privilege) === -1)
            history.replace(hirRouteNames.dashboard);
    }
    componentDidMount() {
        const {dispatch} = this.props;
        hirSettingActions.getSettings()(dispatch);
        
        console.log(this.tableContext);
    }
    static getDerivedStateFromProps(props, state) {
        const {settings} = props;
        if(!state.settingsUnused || 
            JSON.stringify(settings) !== JSON.stringify(state.settingsUnused)){
                state.settingsUnused = settings;
                state.settings = settings;
            }
        return state;
    }
    
    cellMapFormat = superProps => props => <EditableCellMapFormat {...props} {...superProps}/>
    getNewValueContext = ({_id, name}) => (context, dataMap) => {
        if(dataMap === "value"){
            if(this.newSettingValueContext){
                this.newSettingValueContext[name] = context;
            }else this.newSettingValueContext = {[name] : context};
        }            
    }
    addButtonHandler = ({_id, name, header}) => length => () => {
        const {value} = this.newSettingValueContext[name].state.data;
        const {dispatch} = this.props;
        if(!value || !String(value).trim()){
            appActions.showSnackbar(
                alertAction.error("value for "+header+" can not be empty")
            )(dispatch);
            return;
        }
        hirSettingActions.addSettingValue({
            settingId : _id, 
            settingName : name, 
            value
        }, (done)=>{
            if(done) this.newSettingValueContext[name].setState(state => ({data : {...state.data, value : ""}}));
        })(dispatch);
    }

    editBtnHandler = ({_id}) => row => () => {
        const {settings} = this.state;
        if(settings){
            const newSettings = [
                ...settings.map(
                    item=>{
                        return item._id === _id ? 
                        {...item, values : 
                            [...item.values.map(v=>{
                                return v.name === row.name ? 
                                    {...v, editing : true} :
                                v;
                            })]
                        }
                        : item
                    }                    
                )
            ]
            this.setState({settings : newSettings})
        }
    }
    deleteBtnHandler = ({_id, header}) => row => () => {
        const {dispatch} = this.props;
        appActions.showSnackDialog("Are you want to delete "+row.value+" from "+header+"?", [
            <Button key={"delete"+_id} onClick={this.deleteSettingValue(_id, row)}>
                Delete
            </Button>
        ])(dispatch);
    }
    deleteSettingValue = (settingId, row) => () => {
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        hirSettingActions.deleteSettingValue(settingId, row.name)(dispatch);
    }
    editFinishBtnHandler = ({_id, header}) => (row) => () => {
        console.log(row);
        const {dispatch} = this.props;
        const {value} = row.context.value.state.data;
        if(!String(value).trim()){
            appActions.showSnackbar(
                alertAction.error("Value of "+header+" can not be empty")
            )(dispatch);
            return;
        }
        appActions.showSnackDialog(
            "Are you sure you want to modify this item?",
            [<Button key={"edit"+_id} onClick={this.editSettingValue(_id, row.name, value)}>
                Modify
            </Button>]
        )(dispatch);
    }
    editSettingValue = (settingId, valueName, value) => ()=> {
        console.log(settingId, valueName, value);
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        hirSettingActions.editSettingValue(settingId, valueName, value, done => {
            if(done) this.cancelEditBtnHandler({_id : settingId})({name : valueName});
        })(dispatch);
    }
    cancelEditBtnHandler = ({_id}) => row => () => {
        const {settings} = this.state;
        if(settings){
            const newSettings = [
                ...settings.map(
                    item=>{
                        return item._id === _id ? 
                        {...item, values : 
                            [...item.values.map(v=>{
                                if(v.name === row.name)
                                    delete v.editing;
                                return v;
                            })]
                        }
                        : item
                    }                    
                )
            ]
            this.setState({settings : newSettings})
        }
    }
    render() {
        const {classes} = this.props;
        const {settings} = this.state;
        return (
            <div className={classes.root}>
                {settings && settings.map((item, index)=>{
                    const data = item.values ? 
                        [...item.values.map(item=>({...item, editable : true, delible : true})), {new : true}] : 
                        [{new : true}];
                    return <ExpansionPanel key={index}>
                        <ExpansionPanelSummary className={classes.summary}>
                            {item.header}
                        </ExpansionPanelSummary>
                        <ExpansionPanelDetails className={classes.details}>
                            <MyTable
                                elevation={0}
                                header={["Values", "Actions"]}
                                dataMap={["value", "action"]}
                                CellMap={this.cellMapFormat({
                                    getContext : this.getNewValueContext(item),
                                    addButtonHandler : this.addButtonHandler(item),
                                    editBtnHandler : this.editBtnHandler(item),
                                    deleteBtnHandler : this.deleteBtnHandler(item),
                                    editFinishBtnHandler : this.editFinishBtnHandler(item),
                                    cancelEditBtnHandler : this.cancelEditBtnHandler(item),
                                })}
                                data={data}
                                />
                        </ExpansionPanelDetails>
                    </ExpansionPanel>
                })}
            </div>
        );
    }
}


_HIRSettings.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({hirSettingReducer}) => ({
    [hirSettingStrings.settings] : hirSettingReducer[hirSettingStrings.settings],
})


export const HIRSettings = connect(mapStateToProps)(withStyles(style)(_HIRSettings));
export {HIRSettings as default}